    public static void main(String[] args) {
        StockExchange ex = new StockExchange();
        Stock aapl = new Stock("AAPL", "Apple");
        ex.registerStock(aapl);
        Trader a = ex.registerTrader("t1", "A");
        Trader b = ex.registerTrader("t2", "B");
        ex.placeLimitOrder(a, aapl, OrderSide.BUY, 100, 150.0);
